INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) VALUES (32, '4', 'Ahlaki ve etik değerlere uygun davranır. Davranışlarının sorumluluğunu üstlenir.', 4);
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) VALUES (33, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.', 5);
INSERT INTO position_questions (categoryId, questionNumber, questionText, `order`) VALUES (33, '6', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır.', 6);
